1	\chapter{The Jacobian as an abelian variety}
2	\label{chap:Jacobian}
3	
4	Let $C$ be a smooth proper curve over $k$ in the sense of Chapter~\ref{chap:Genus}, with genus $g = g(C)$.
5	
6	Because the Picard-scheme machinery (Chapter~\ref{chap:Picard_Functor}) is blocked at the level of monoidal-category infrastructure for $\mathcal O_X$-modules and the full FGA representability theorem, this chapter builds the Jacobian by an alternative ad-hoc route: the Albanese functor on smooth proper curves.
7	
8	\section{The Albanese construction}
9	
10	For a smooth proper curve $C$ over $k$, the Albanese variety is the universal abelian variety receiving a morphism from $C$. Over an algebraically closed field this is classically identified with the connected component of the identity of the Picard scheme, but we construct it directly from symmetric powers.
11	
12	\subsection{Symmetric powers and the Abel--Jacobi map}
13	
14	Let $C^{(g)} = \Sym^g(C)$ be the $g$\textsuperscript{th} symmetric power of $C$ (the quotient of $C^g$ by the action of the symmetric group $S_g$). It is a smooth proper scheme over $k$ of dimension $g$. Fix a $k$-rational point $P_0 \in C(k)$. The map
15	\[
16	  \sigma \colon C^{(g)} \longrightarrow \Pic^g_{C/k}, \qquad
17	  \sum_{i=1}^g [P_i] \longmapsto \mathcal O_C\bigl(\textstyle\sum_{i=1}^g P_i - g P_0\bigr)
18	\]
19	is surjective and birational onto its image; its fibres are projective spaces (Brill--Noether--Riemann--Roch). Choosing $P_0$ gives a translation isomorphism $\Pic^g_{C/k} \xrightarrow{\;\sim\;} \Pic^0_{C/k}$, and the Stein factorisation of $\sigma$ yields the Jacobian as the connected component of the identity.
20	
21	In the Lean formalisation we do not have general symmetric powers of schemes (or quotients by finite group actions) in Mathlib. We therefore take a more direct approach: we define the Jacobian as the Albanese object of $C$ inside the category of smooth proper group schemes over $k$, using the universal property and the known dimension formula.
22	
23	\subsection{The Albanese universal property}
24	
25	\begin{definition}\leanok
26	[Albanese universal property of a pointed curve]
27	  \label{def:IsAlbanese}
28	  \lean{AlgebraicGeometry.IsAlbanese}
29	  Let $(C, P)$ be a smooth proper geometrically irreducible curve over $k$ with a marked $k$-rational point $P \in C(k)$. A smooth proper geometrically irreducible group scheme $J$ over $k$ is an \emph{Albanese object} for $(C, P)$ if there exists a morphism $\iota \colon C \to J$ sending $P$ to the identity element $\eta \in J$, and such that every morphism $f \colon C \to A$ from $C$ to a smooth proper geometrically irreducible group scheme $A$ with $f(P) = \eta_A$ factors uniquely as $f = \iota \circ g$ for some morphism of group schemes $g \colon J \to A$.
30	\end{definition}
31	
32	\begin{theorem}\leanok
33	[Uniqueness of the Albanese object]
34	  \label{thm:IsAlbanese_unique}
35	  \lean{AlgebraicGeometry.IsAlbanese.unique}
36	  \uses{def:IsAlbanese}
37	  Any two Albanese objects for the same pointed curve $(C, P)$ are uniquely isomorphic by an isomorphism compatible with their universal morphisms. The proof is the standard universal-property argument: each of the two universal morphisms factors through the other, the two composites equal the unique self-factorisation $\mathrm{id}$, hence each factorisation is an isomorphism.
38	\end{theorem}
39	
40	\subsection{The Jacobian definition}
41	
42	\begin{definition}\leanok
43	[Jacobian]
44	  \label{def:Jacobian}
45	  \lean{AlgebraicGeometry.Jacobian}
46	  \uses{def:genus, def:IsAlbanese, thm:nonempty_jacobianWitness}
47	  The \emph{Jacobian} of $C$ is the abelian variety $\Jac(C)$ over $k$ obtained as the Albanese object of $C$: a smooth proper geometrically irreducible group scheme over $k$ of dimension $g(C)$ equipped with a universal morphism $C \to \Jac(C)$ (for each choice of marked point). It is viewed as an object of the category of $k$-schemes over $\Spec k$. Formally, $\Jac(C)$ is defined as the underlying scheme of a (uniform-over-$P$) Albanese witness for $C$ provided by Theorem~\ref{thm:nonempty_jacobianWitness}.
48	
49	  When $g(C) = 0$ the Jacobian collapses to $\Spec k$ itself, which is the terminal object in the category of $k$-schemes. When $g(C) > 0$ the underlying scheme is the abelian variety produced by Theorem~\ref{thm:nonempty_jacobianWitness}; the genus-one case recovers $C$ itself (after choosing a $k$-rational point), and the higher genus case yields the non-trivial $g$-dimensional abelian variety. Both cases are handled uniformly: $\Jac(C)$ is the underlying scheme of the Albanese witness, with no special-case branching at the level of the definition. The genus-$0$ specialisation is implicit in the fact that any group scheme over $k$ of relative dimension $0$ is isomorphic to $\Spec k$.
50	\end{definition}
51	
52	\section{Group scheme structure and abelian-variety properties}
53	
54	\begin{theorem}\leanok
55	[Group object structure]
56	  \label{thm:Jacobian_grpObj}
57	  \lean{AlgebraicGeometry.Jacobian.instGrpObj}
58	  \uses{def:Jacobian}
59	  $\Jac(C)$ carries a canonical group-object structure in the category of $k$-schemes over $\Spec k$, induced by the Albanese universal property and the cogroup structure of $C$ in the category of pointed curves.
60	\end{theorem}
61	
62	\begin{theorem}\leanok
63	[Smoothness and dimension]
64	  \label{thm:Jacobian_smooth_genus}
65	  \lean{AlgebraicGeometry.Jacobian.smoothOfRelativeDimension_genus}
66	  \uses{def:Jacobian, def:genus}
67	  $\Jac(C) \to \Spec k$ is smooth of relative dimension $g(C)$.
68	\end{theorem}
69	
70	\begin{theorem}\leanok
71	[Properness]
72	  \label{thm:Jacobian_proper}
73	  \lean{AlgebraicGeometry.Jacobian.instIsProper}
74	  \uses{def:Jacobian}
75	  $\Jac(C) \to \Spec k$ is proper.
76	\end{theorem}
77	
78	\begin{theorem}\leanok
79	[Geometric irreducibility]
80	  \label{thm:Jacobian_geomIrred}
81	  \lean{AlgebraicGeometry.Jacobian.instGeometricallyIrreducible}
82	  \uses{def:Jacobian}
83	  $\Jac(C) \to \Spec k$ is geometrically irreducible.
84	\end{theorem}
85	
86	All four properties are part of the Albanese construction. Smoothness and dimension follow from the deformation-theoretic identification of the tangent space at the identity with $H^1(C, \mathcal O_C)$ (Phase~A, Chapter~\ref{chap:Cohomology_StructureSheafAb}). Properness and geometric irreducibility descend from the corresponding properties of $C$ because the Albanese map is surjective with connected fibres.
87	
88	\subsection{Sanity check in low genus}
89	
90	\begin{itemize}
91	  \item $g = 0$: Then $\Jac(C) = \Spec k$, the trivial group scheme; $\Jac(\mathbb P^1_k) = \Spec k$ is smooth of relative dimension $0 = g$.
92	  \item $g = 1$: Then $\Jac(C) \cong C$ once a $k$-rational point on $C$ is fixed; $C$ is itself an elliptic curve (abelian variety of dimension $1$).
93	  \item $g \ge 2$: $\Jac(C)$ is a non-trivial $g$-dimensional abelian variety, never isomorphic to $C$ as a scheme.
94	\end{itemize}
95	
96	\section{Existence of an Albanese variety}
97	
98	The classical construction of the Jacobian goes through the Picard scheme machinery: $\Jac(C)$ is the connected component of the identity of $\Pic^0_{C/k}$. An equivalent route, available whenever a $k$-rational point $P \in C(k)$ has been fixed, is to take the Stein factorisation of the Abel--Jacobi morphism $\Sym^g(C) \to \Pic^g_{C/k}$ and translate by $-gP$.
99	
100	\begin{theorem}\leanok
101	[Existence of an Albanese variety uniformly over the marked point]
102	  \label{thm:nonempty_jacobianWitness}
103	  \lean{AlgebraicGeometry.nonempty_jacobianWitness}
104	  \uses{def:IsAlbanese, def:Jacobian, def:genus}
105	  Let $C$ be a smooth proper geometrically irreducible curve over a field $k$. There exists a smooth proper geometrically irreducible group scheme $J$ over $k$ of relative dimension $g(C)$ such that, for every $k$-rational point $P \in C(k)$, the scheme $J$ is an Albanese object for the pointed curve $(C, P)$ in the sense of Definition~\ref{def:IsAlbanese}.
106	\end{theorem}
107	
108	\begin{proof}
109	  \uses{def:IsAlbanese}
110	  \leanok
111	  The underlying scheme $J$ depends only on $C$, not on the choice of marked point; only the universal morphism $\iota_P \colon C \to J$ varies with $P$. Two classical constructions provide $J$:
112	  \begin{itemize}
113	    \item $g(C) \ge 1$: (i) take $J = \Pic^0_{C/k}$, the connected component of the identity of the Picard scheme; for every $P \in C(k)$, the Abel--Jacobi map $\iota_P \colon C \to \Pic^0_{C/k}$, $Q \mapsto [\mathcal O_C(Q - P)]$, sends $P$ to the identity and satisfies the universal property by the universal property of $\Pic^0_{C/k}$. Equivalently, (ii) form the Stein factorisation of $\Sym^g(C) \to \Pic^g_{C/k}$ translated by $-gP$. Both routes yield a smooth proper geometrically irreducible group scheme of dimension $g(C)$.
114	    \item $g(C) = 0$: take $J = \Spec k$, the trivial $k$-group scheme of dimension $0$. The Albanese universal property in this case reduces to the rigidity assertion that every morphism $f \colon C \to A$ from a smooth proper geometrically irreducible genus-$0$ curve $C$ to a smooth proper geometrically irreducible group scheme $A$ with $f(P) = \eta_A$ is the constant morphism at $\eta_A$. Classically, this follows from $\Hom(\mathbb P^1_k, A) = A(k)$ together with the fact that a genus-$0$ curve with a $k$-rational point is isomorphic to $\mathbb P^1_k$ (Brauer--Severi). The unique morphism $\Spec k \to A$ then provides the required factorisation.
115	  \end{itemize}
116	  Mathlib currently contains neither Pic-scheme representability, nor symmetric powers / quotients of schemes by finite group actions, nor the rigidity theorem $\Hom(\mathbb P^1_k, A) = A(k)$ for morphisms to abelian varieties. The existence statement is therefore recorded here as a single working hypothesis backing all downstream consequences (the four protected instances on $\Jac(C)$, the Abel--Jacobi map and its universal property of Chapter~\ref{chap:AbelJacobi}). Both the higher-genus existence and the genus-$0$ rigidity content are encapsulated in this single hypothesis.
117	\end{proof}
118	
119	\section{Implementation route via the Albanese functor}
120	
121	Because the full Picard-scheme representability theorem is not available in current Mathlib, the formal construction proceeds in two layers:
122	
123	\begin{enumerate}
124	  \item \textbf{Layer I --- direct definition.} The Jacobian of $C$ is defined uniformly as the underlying scheme of the Albanese witness provided by Theorem~\ref{thm:nonempty_jacobianWitness}, carrying the four properties of Theorems~\ref{thm:Jacobian_grpObj}--\ref{thm:Jacobian_geomIrred} (each obtained by projection from the witness). The genus-$0$ case is included: the witness's universal property in that case implicitly carries the rigidity content $\Hom(\mathbb P^1_k, A) = A(k)$.
125	
126	  \item \textbf{Layer II --- Abel--Jacobi compatibility.} Chapter~\ref{chap:AbelJacobi} introduces the Abel--Jacobi morphism $C \to \Jac(C)$ and shows that it is universal among morphisms from $C$ to abelian varieties.
127	\end{enumerate}
